"use strict";const t=require("./random.js");exports.SeedGenerator=class{static fromNumber(t){return Number(t)||Date.now()}static fromText(t){let e=0;for(let r=0;r<t.length;r++)e=(31*e+t.charCodeAt(r))%2**31;return e}static fromQuestion(e,r=5){const n=new t.AdvancedRandomGenerator(Date.now());let o=0;for(let t=0;t<r;t++){const t=n.randomInt(e.length);o=(31*o+e.charCodeAt(t))%2**31}return o}static fromDateTime(t=null){return(t?new Date(t):new Date).getTime()}static compositeSeed(t){let e=0;return t.forEach((t=>{"number"==typeof t?e^=t:"string"==typeof t&&(e^=this.fromText(t))})),Math.abs(e)}static randomParams(e){const r=new t.AdvancedRandomGenerator(e),n=["LCG算法","异或位移","梅森旋转"],o=["lcg","xorshift","mersenne"];return{method:n[r.randomInt(n.length,"lcg")],cards:r.randomInt(5,"lcg")+1,algorithm:o[r.randomInt(o.length,"lcg")]}}};
